"use client";

import { useAuth } from "@/entities/auth";
import { BackButton } from "@/shared/ui/back-button-new/back-button";
import { CreateTicketForm } from "@/widgets/create-ticket-form";
import { useRouter } from "next/navigation";

export default function CreateTicketPage() {
  const router = useRouter();
  const { isAuthenticated, isLoading } = useAuth();

  function handleSuccess(ticketId: string) {
    router.push(isAuthenticated ? `/support/${ticketId}` : "/support");
  }

  return (
    <div className="mx-auto max-w-[600px]">
      <div className="mb-8">
        <BackButton onClick={() => router.back()} label="Back" />
      </div>

      <h1 className="font-light font-new-serif text-[#44403C] text-[2rem] leading-[120%]">
        Raise a Support Ticket
      </h1>
      <p className="mt-2 font-new-sans text-[#A8A29E] text-sm">
        Share enough details to get your issue resolved. Our team will evaluate
        your request and will address it soon.
      </p>

      <div className="my-6 border-[#D6D3D1] border-t" />

      {isLoading ? (
        <div className="flex flex-col gap-4">
          {[1, 2, 3].map((i) => (
            <div key={i} className="h-12 animate-pulse rounded-[4px] bg-[#EDE9E3]" />
          ))}
        </div>
      ) : (
        <CreateTicketForm
          isGuest={!isAuthenticated}
          onSuccess={handleSuccess}
        />
      )}
    </div>
  );
}

"use client";

import {
  useActiveBuybacks,
  useBuybackRequests,
} from "@/shared/api/query-hooks/use-buyback-requests";
import { useFileUpload } from "@/shared/api/query-hooks/use-file-upload";
import { useCreateTicket } from "@/shared/api/query-hooks/use-tickets";
import type { MimeType } from "@/shared/constants/mime-types";
import { S3_FOLDERS } from "@/shared/constants/mime-types";
import { TICKET_CATEGORY_LABELS } from "@/shared/constants/ticket";
import { generateItemTitle, getSecondaryDisplayInfo } from "@/shared/lib/items";
import { sanitizeFileName } from "@/shared/lib/utils/file-name-utils";
import { NotificationMedia, TicketCategory } from "@/shared/types/ticket.types";
import { Checkbox } from "@/shared/ui/checkbox";
import { toast } from "@/shared/ui/notification";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui/select";
import { zodResolver } from "@hookform/resolvers/zod";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { type Resolver, useForm } from "react-hook-form";
import { z } from "zod";
import type { CreateTicketFormProps } from "../model/types";

const MAX_FILES = 5;
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5 MB

const createTicketSchema = z.object({
  description: z
    .string()
    .min(1, "Description is required")
    .min(5, "Description must be at least 5 characters")
    .max(2000, "Description must be less than 2000 characters"),
  category: z.nativeEnum(TicketCategory, {
    errorMap: () => ({ message: "Please select a category" }),
  }),
  referenceId: z.string().optional(),
  attachedFileIds: z
    .array(z.string())
    .max(MAX_FILES, `Maximum ${MAX_FILES} files allowed`),
  preferredContactMethods: z
    .array(z.nativeEnum(NotificationMedia))
    .min(1, "Select at least one contact method"),
});

const guestCreateTicketSchema = createTicketSchema.extend({
  fullName: z
    .string()
    .min(1, "Full name is required")
    .min(2, "Name must be at least 2 characters"),
  email: z
    .string()
    .min(1, "Email is required")
    .email("Please enter a valid email"),
});

type GuestCreateTicketFormData = z.infer<typeof guestCreateTicketSchema>;

export function CreateTicketForm({
  onSuccess,
  onCancel,
  isGuest = false,
}: CreateTicketFormProps) {
  const [uploadedFiles, setUploadedFiles] = useState<
    Array<{ id: string; name: string }>
  >([]);
  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
  const [isDragOver, setIsDragOver] = useState(false);
  const [referenceSearch, setReferenceSearch] = useState("");
  const [debouncedSearch, setDebouncedSearch] = useState("");
  const [isReferenceSelectOpen, setIsReferenceSelectOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const createTicketMutation = useCreateTicket();
  const fileUploadMutation = useFileUpload();

  const schema = isGuest ? guestCreateTicketSchema : createTicketSchema;

  const {
    register,
    handleSubmit,
    watch,
    setValue,
    formState: { errors },
  } = useForm<GuestCreateTicketFormData>({
    resolver: zodResolver(
      schema
    ) as unknown as Resolver<GuestCreateTicketFormData>,
    defaultValues: {
      attachedFileIds: [],
      preferredContactMethods: [NotificationMedia.Email],
    },
  });

  const selectedCategory = watch("category");
  const selectedContactMethods = watch("preferredContactMethods");
  const selectedReferenceId = watch("referenceId");

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearch(referenceSearch);
    }, 300);

    return () => clearTimeout(timer);
  }, [referenceSearch]);

  const { data: buybacksData, isLoading: isLoadingBuybacks } =
    useActiveBuybacks({ search: debouncedSearch || undefined }, !isGuest);

  const { data: buybackRequestsData, isLoading: isLoadingBuybackRequests } =
    useBuybackRequests({ search: debouncedSearch || undefined }, !isGuest);

  function handleContactMethodToggle(method: NotificationMedia) {
    const current = selectedContactMethods || [];

    if (current.includes(method)) {
      const newMethods = current.filter((m) => m !== method);

      if (newMethods.length === 0) {
        toast.error("At least one contact method is required");

        return;
      }

      setValue("preferredContactMethods", newMethods, { shouldValidate: true });
    } else {
      setValue("preferredContactMethods", [...current, method], {
        shouldValidate: true,
      });
    }
  }

  async function processFiles(files: File[]) {
    const remainingSlots = MAX_FILES - uploadedFiles.length;

    if (remainingSlots <= 0) {
      toast.error(`Maximum ${MAX_FILES} files allowed`);

      return;
    }

    const filesToProcess = files.slice(0, remainingSlots);
    const oversized = files.filter((f) => f.size > MAX_FILE_SIZE);

    if (oversized.length > 0) {
      toast.error(`${oversized.length} file(s) exceed the 5 MB limit`);
    }

    const validFiles = filesToProcess.filter((f) => f.size <= MAX_FILE_SIZE);

    if (validFiles.length === 0) return;

    setIsUploadingFiles(true);

    const uploadResults: Array<{ id: string; name: string }> = [];

    for (const file of validFiles) {
      try {
        const fileNameInfo = sanitizeFileName(file.name);

        const result = await fileUploadMutation.mutateAsync({
          file,
          mime: file.type as MimeType,
          fileName: fileNameInfo.sanitized,
          folder: S3_FOLDERS.FILES,
        });

        uploadResults.push({ id: result.fileId, name: fileNameInfo.original });
      } catch {
        toast.error(`Failed to upload ${file.name}`);
      }
    }

    const newUploadedFiles = [...uploadedFiles, ...uploadResults];

    setUploadedFiles(newUploadedFiles);
    setValue(
      "attachedFileIds",
      newUploadedFiles.map((f) => f.id),
      { shouldValidate: true }
    );

    setIsUploadingFiles(false);
  }

  function handleRemoveFile(fileId: string) {
    const newUploadedFiles = uploadedFiles.filter((f) => f.id !== fileId);

    setUploadedFiles(newUploadedFiles);
    setValue(
      "attachedFileIds",
      newUploadedFiles.map((f) => f.id),
      { shouldValidate: true }
    );
  }

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragOver(false);
  }, []);

  function handleDrop(e: React.DragEvent) {
    e.preventDefault();
    setIsDragOver(false);

    const files = Array.from(e.dataTransfer.files);
    const accepted = files.filter((f) =>
      ["application/pdf", "image/jpeg", "image/png"].includes(f.type)
    );

    if (accepted.length < files.length) {
      toast.error("Only .PDF, .JPG, .PNG files are supported");
    }

    if (accepted.length > 0) {
      processFiles(accepted);
    }
  }

  // biome-ignore lint/suspicious/noExplicitAny: dynamic schema union
  async function onSubmit(data: any) {
    const subject = data.description.slice(0, 100).trim() || "Support Request";

    createTicketMutation.mutate(
      {
        subject: isGuest ? undefined : subject,
        description: data.description,
        category: data.category,
        referenceId: data.referenceId,
        attachedFileIds: data.attachedFileIds,
        preferredContactMethods: data.preferredContactMethods,
        fullName: isGuest ? data.fullName : undefined,
        email: isGuest ? data.email : undefined,
      },
      {
        onSuccess: (ticket) => {
          toast.success("Ticket submitted successfully");
          onSuccess?.(ticket.id);
        },
        onError: () => {
          toast.error("Failed to create ticket");
        },
      }
    );
  }

  const referenceOptions = useMemo(() => {
    if (selectedCategory === TicketCategory.ActiveBuyback) {
      return (
        buybacksData?.data.map((b) => {
          const asset = b.asset;
          const itemTitle = generateItemTitle(
            asset.category.name,
            asset.categoryFields
          );
          const secondaryInfo = getSecondaryDisplayInfo(
            asset.category.name,
            asset.categoryFields
          );

          return {
            value: b.id,
            label: `Buyback #${b.id.slice(0, 8)}`,
            details: `${itemTitle} · ${secondaryInfo}`,
          };
        }) || []
      );
    }

    if (selectedCategory === TicketCategory.BuybackRequest) {
      return (
        buybackRequestsData?.data.map((br) => {
          const asset = br.buyback.asset;
          const itemTitle = generateItemTitle(
            asset.category.name,
            asset.categoryFields
          );
          const secondaryInfo = getSecondaryDisplayInfo(
            asset.category.name,
            asset.categoryFields
          );

          return {
            value: br.id,
            label: `Request #${br.id.slice(0, 8)}`,
            details: `${itemTitle} · ${secondaryInfo}`,
          };
        }) || []
      );
    }

    return [];
  }, [selectedCategory, buybacksData, buybackRequestsData]);

  const isLoadingReference =
    selectedCategory === TicketCategory.ActiveBuyback
      ? isLoadingBuybacks
      : isLoadingBuybackRequests;

  const showReferenceSelect =
    !isGuest &&
    (selectedCategory === TicketCategory.ActiveBuyback ||
      selectedCategory === TicketCategory.BuybackRequest);

  const descriptionValue = watch("description") || "";
  const isSubmitting = createTicketMutation.isPending || isUploadingFiles;

  return (
    <form className="flex flex-col gap-6" onSubmit={handleSubmit(onSubmit)}>
      {/* Guest fields */}
      {isGuest && (
        <div className="flex flex-col gap-4 sm:flex-row">
          <div className="flex flex-1 flex-col gap-1.5">
            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
              Full Name <span className="text-red-500">*</span>
            </label>
            <input
              {...register("fullName")}
              className="h-12 rounded-[4px] border border-[#A8A29E] bg-transparent px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171]"
              placeholder="Your full name"
            />
            {errors.fullName && (
              <p className="font-new-sans text-red-500 text-xs">
                {errors.fullName.message}
              </p>
            )}
          </div>
          <div className="flex flex-1 flex-col gap-1.5">
            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              {...register("email")}
              className="h-12 rounded-[4px] border border-[#A8A29E] bg-transparent px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171]"
              placeholder="your@email.com"
              type="email"
            />
            {errors.email && (
              <p className="font-new-sans text-red-500 text-xs">
                {errors.email.message}
              </p>
            )}
          </div>
        </div>
      )}

      {/* Category */}
      <div className="flex flex-col gap-1.5">
        <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
          Category
        </label>
        <Select
          onValueChange={(value) =>
            setValue("category", value as TicketCategory, {
              shouldValidate: true,
            })
          }
        >
          <SelectTrigger
            className={`h-12 rounded-[4px] border font-new-sans text-[#44403C] text-sm ${
              errors.category ? "border-red-400" : "border-[#A8A29E]"
            }`}
          >
            <SelectValue placeholder="Select an option" />
          </SelectTrigger>
          <SelectContent>
            {Object.values(TicketCategory).map((category) => (
              <SelectItem key={category} value={category}>
                {TICKET_CATEGORY_LABELS[category]}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
        {errors.category && (
          <p className="font-new-sans text-red-500 text-xs">
            {errors.category.message}
          </p>
        )}
      </div>

      {/* Related order */}
      {showReferenceSelect && (
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-2">
            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
              Related order
            </label>
            <svg
              aria-hidden="true"
              className="text-[#A8A29E]"
              fill="none"
              height="14"
              viewBox="0 0 16 16"
              width="14"
            >
              <circle
                cx="8"
                cy="8"
                r="7"
                stroke="currentColor"
                strokeWidth="1.2"
              />
              <path
                d="M8 7v5M8 5.5v-.5"
                stroke="currentColor"
                strokeLinecap="round"
                strokeWidth="1.4"
              />
            </svg>
            <span className="ml-auto rounded bg-[#EDE9E3] px-2 py-0.5 font-new-sans text-[#A8A29E] text-xs">
              Optional
            </span>
          </div>
          <Select
            onOpenChange={setIsReferenceSelectOpen}
            onValueChange={(value) => {
              setValue("referenceId", value);
              setIsReferenceSelectOpen(false);
              setReferenceSearch("");
            }}
            open={isReferenceSelectOpen}
            value={selectedReferenceId}
          >
            <SelectTrigger className="h-12 rounded-[4px] border border-[#A8A29E] font-new-sans text-[#44403C] text-sm">
              <SelectValue placeholder="Select an existing order if applicable" />
            </SelectTrigger>
            <SelectContent className="p-0">
              <div className="border-[#D6D3D1] border-b p-2">
                <input
                  className="h-8 w-full rounded border border-[#D6D3D1] px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none"
                  onChange={(e) => setReferenceSearch(e.target.value)}
                  onClick={(e) => e.stopPropagation()}
                  onKeyDown={(e) => e.stopPropagation()}
                  placeholder="Search..."
                  value={referenceSearch}
                />
              </div>
              <div className="max-h-[260px] overflow-y-auto">
                {isLoadingReference && (
                  <div className="py-6 text-center font-new-sans text-[#A8A29E] text-sm">
                    Searching...
                  </div>
                )}
                {!isLoadingReference && referenceOptions.length === 0 && (
                  <div className="py-6 text-center font-new-sans text-[#A8A29E] text-sm">
                    {debouncedSearch
                      ? "No results found"
                      : "No items available"}
                  </div>
                )}
                {!isLoadingReference &&
                  referenceOptions.map((option) => (
                    <SelectItem
                      className="cursor-pointer"
                      key={option.value}
                      value={option.value}
                    >
                      <div className="flex flex-col gap-0.5">
                        <span className="font-medium font-new-sans text-[#44403C]">
                          {option.label}
                        </span>
                        <span className="font-new-sans text-[#A8A29E] text-xs">
                          {option.details}
                        </span>
                      </div>
                    </SelectItem>
                  ))}
              </div>
            </SelectContent>
          </Select>
          <p className="font-new-sans text-[#A8A29E] text-xs">
            Select from your previous buybacks, permanent sales, or purchases.
          </p>
        </div>
      )}

      {/* Description */}
      <div className="flex flex-col gap-1.5">
        <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
          Ticket Description <span className="text-red-500">*</span>
        </label>
        <textarea
          {...register("description")}
          className={`resize-none rounded-[4px] border px-3 py-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171] ${
            errors.description ? "border-red-400" : "border-[#A8A29E]"
          }`}
          maxLength={2100}
          placeholder="Enter your message here"
          rows={5}
        />
        <div className="flex items-center justify-between">
          {errors.description ? (
            <p className="font-new-sans text-red-500 text-xs">
              {errors.description.message}
            </p>
          ) : (
            <span />
          )}
          <span
            className={`font-new-sans text-xs ${
              descriptionValue.length > 2000 ? "text-red-500" : "text-[#A8A29E]"
            }`}
          >
            {descriptionValue.length}/2000
          </span>
        </div>
      </div>

      {/* Attach Support Files */}
      <div className="rounded-xl border border-[#D6D3D1] bg-white p-5">
        <h3 className="font-light font-new-serif text-[#44403C] text-xl leading-[120%]">
          Attach Support Files
        </h3>
        <p className="mt-1 font-new-sans text-[#A8A29E] text-sm">
          Search or drop your files here. Upload up to {MAX_FILES} files.
          <br />
          Supported formats: .PDF, .JPG, .PNG. Max file size: 5mb.
        </p>

        <div className="mt-4 flex flex-col gap-2">
          {uploadedFiles.map((file) => (
            <div
              className="flex items-center gap-3 rounded-[4px] border border-[#D6D3D1] px-3 py-2.5"
              key={file.id}
            >
              <svg
                aria-hidden="true"
                className="shrink-0 text-[#44403C]"
                fill="none"
                height="16"
                viewBox="0 0 24 24"
                width="16"
              >
                <path
                  d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"
                  stroke="currentColor"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth="1.5"
                />
              </svg>
              <span className="flex-1 truncate font-new-sans text-[#44403C] text-sm">
                {file.name}
              </span>
              <button
                aria-label="Remove file"
                className="shrink-0 rounded p-1 text-[#A8A29E] transition-colors hover:text-red-500"
                onClick={() => handleRemoveFile(file.id)}
                type="button"
              >
                <svg
                  aria-hidden="true"
                  fill="none"
                  height="16"
                  viewBox="0 0 24 24"
                  width="16"
                >
                  <path
                    d="M3 6h18M8 6V4h8v2M19 6l-1 14H6L5 6"
                    stroke="currentColor"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth="1.5"
                  />
                </svg>
              </button>
            </div>
          ))}

          {uploadedFiles.length < MAX_FILES && (
            <button
              className={`flex h-12 items-center justify-center gap-2 rounded-[4px] border border-dashed font-new-sans text-sm transition-colors ${
                isDragOver
                  ? "border-[#021171] bg-blue-50 text-[#021171]"
                  : "border-[#A8A29E] text-[#44403C] hover:border-[#44403C]"
              } ${isUploadingFiles ? "cursor-not-allowed opacity-60" : "cursor-pointer"}`}
              disabled={isUploadingFiles}
              onClick={() => fileInputRef.current?.click()}
              onDragLeave={handleDragLeave}
              onDragOver={handleDragOver}
              onDrop={handleDrop}
              type="button"
            >
              {isUploadingFiles ? (
                "Uploading..."
              ) : (
                <>
                  Find or drop a new file
                  <svg
                    aria-hidden="true"
                    fill="none"
                    height="16"
                    viewBox="0 0 16 16"
                    width="16"
                  >
                    <path
                      d="M8 3v10M3 8h10"
                      stroke="currentColor"
                      strokeLinecap="round"
                      strokeWidth="1.5"
                    />
                  </svg>
                </>
              )}
            </button>
          )}

          <input
            accept=".pdf,.jpg,.jpeg,.png"
            className="hidden"
            multiple
            onChange={(e) => {
              const files = Array.from(e.target.files || []);
              processFiles(files);
              e.target.value = "";
            }}
            ref={fileInputRef}
            type="file"
          />
        </div>

        {errors.attachedFileIds && (
          <p className="mt-2 font-new-sans text-red-500 text-xs">
            {errors.attachedFileIds.message}
          </p>
        )}
      </div>

      {/* Preferred Response */}
      <div className="rounded-xl border border-[#D6D3D1] bg-white p-5">
        <h3 className="font-light font-new-serif text-[#44403C] text-xl leading-[120%]">
          Preferred Response
        </h3>

        <div className="mt-4 flex flex-col gap-4">
          <label className="flex cursor-pointer items-center gap-3">
            <svg
              aria-hidden="true"
              className="shrink-0 text-[#44403C]"
              fill="none"
              height="18"
              viewBox="0 0 24 24"
              width="18"
            >
              <path
                d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9M13.73 21a2 2 0 01-3.46 0"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="1.5"
              />
            </svg>
            <span className="flex-1 font-new-sans text-[#44403C] text-sm">
              In-App Notification
            </span>
            <Checkbox
              checked={selectedContactMethods?.includes(
                NotificationMedia.InApp
              )}
              className="rounded-[3px]"
              onCheckedChange={() =>
                handleContactMethodToggle(NotificationMedia.InApp)
              }
            />
          </label>

          <label className="flex cursor-pointer items-center gap-3">
            <svg
              aria-hidden="true"
              className="shrink-0 text-[#44403C]"
              fill="none"
              height="18"
              viewBox="0 0 24 24"
              width="18"
            >
              <path
                d="M4 4h16c1.1 0 2 .9 2 2v12c0 1.1-.9 2-2 2H4c-1.1 0-2-.9-2-2V6c0-1.1.9-2 2-2z"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="1.5"
              />
              <polyline
                points="22,6 12,13 2,6"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="1.5"
              />
            </svg>
            <span className="flex-1 font-new-sans text-[#44403C] text-sm">
              Email
            </span>
            <Checkbox
              checked={selectedContactMethods?.includes(
                NotificationMedia.Email
              )}
              className="rounded-[3px]"
              onCheckedChange={() =>
                handleContactMethodToggle(NotificationMedia.Email)
              }
            />
          </label>

          <label className="flex cursor-pointer items-center gap-3">
            <svg
              aria-hidden="true"
              className="shrink-0 text-[#44403C]"
              fill="none"
              height="18"
              viewBox="0 0 24 24"
              width="18"
            >
              <path
                d="M22 16.92v3a2 2 0 01-2.18 2 19.79 19.79 0 01-8.63-3.07A19.5 19.5 0 013.07 10.8a19.79 19.79 0 01-3.07-8.68A2 2 0 012.18 0h3a2 2 0 012 1.72c.127.96.361 1.903.7 2.81a2 2 0 01-.45 2.11L6.91 7.09a16 16 0 006 6l.56-.56a2 2 0 012.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0122 14.92z"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="1.5"
              />
            </svg>
            <span className="flex-1 font-new-sans text-[#44403C] text-sm">
              Phone Call
            </span>
            <Checkbox
              checked={selectedContactMethods?.includes(
                NotificationMedia.Phone
              )}
              className="rounded-[3px]"
              onCheckedChange={() =>
                handleContactMethodToggle(NotificationMedia.Phone)
              }
            />
          </label>
        </div>

        {errors.preferredContactMethods && (
          <p className="mt-2 font-new-sans text-red-500 text-xs">
            {errors.preferredContactMethods.message}
          </p>
        )}
      </div>

      <div className="flex flex-col gap-3 sm:flex-row">
        {onCancel && (
          <button
            className="flex h-12 items-center justify-center rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-6 font-medium font-new-sans text-[#44403C] transition-colors hover:bg-[#EDE9E3] disabled:opacity-50"
            disabled={isSubmitting}
            onClick={onCancel}
            type="button"
          >
            Cancel
          </button>
        )}
        <button
          className="flex h-12 items-center justify-center gap-2 rounded-lg bg-[#021171] px-8 font-medium font-new-sans text-[#F5F3EF] transition-opacity hover:opacity-90 disabled:opacity-50"
          disabled={isSubmitting}
          type="submit"
        >
          {isSubmitting ? (
            "Submitting..."
          ) : (
            <>
              Submit Ticket
              <svg
                aria-hidden="true"
                fill="none"
                height="16"
                viewBox="0 0 16 16"
                width="16"
              >
                <path
                  d="M3 8h10M9 4l4 4-4 4"
                  stroke="currentColor"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth="1.5"
                />
              </svg>
            </>
          )}
        </button>
      </div>
    </form>
  );
}

"use client";

import * as SheetPrimitive from "@radix-ui/react-dialog";
import type * as React from "react";
import { CloseOutline } from "react-ionicons";
import { cn } from "../../lib/ui/cn";

function Sheet({ ...props }: React.ComponentProps<typeof SheetPrimitive.Root>) {
  return <SheetPrimitive.Root data-slot="sheet" {...props} />;
}

function SheetTrigger({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Trigger>) {
  return <SheetPrimitive.Trigger data-slot="sheet-trigger" {...props} />;
}

function SheetClose({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Close>) {
  return <SheetPrimitive.Close data-slot="sheet-close" {...props} />;
}

function SheetPortal({
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Portal>) {
  return <SheetPrimitive.Portal data-slot="sheet-portal" {...props} />;
}

function SheetOverlay({
  className,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Overlay>) {
  return (
    <SheetPrimitive.Overlay
      data-slot="sheet-overlay"
      className={cn(
        "data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 fixed inset-0 z-50 bg-black/50 data-[state=closed]:animate-out data-[state=open]:animate-in",
        className,
      )}
      {...props}
    />
  );
}

function SheetContent({
  className,
  children,
  side = "right",
  hideCloseButton = false,
  ...props
}: React.ComponentProps<typeof SheetPrimitive.Content> & {
  side?: "top" | "right" | "bottom" | "left";
  hideCloseButton?: boolean;
}) {
  return (
    <SheetPortal>
      <SheetOverlay />
      <SheetPrimitive.Content
        data-slot="sheet-content"
        className={cn(
          "fixed z-50 flex flex-col gap-4 bg-background shadow-lg transition ease-in-out data-[state=closed]:animate-out data-[state=open]:animate-in data-[state=closed]:duration-300 data-[state=open]:duration-500",
          side === "right" &&
            "data-[state=closed]:slide-out-to-right data-[state=open]:slide-in-from-right inset-y-0 right-0 h-full border-l",
          side === "left" &&
            "data-[state=closed]:slide-out-to-left data-[state=open]:slide-in-from-left inset-y-0 left-0 h-full border-r",
          side === "top" &&
            "data-[state=closed]:slide-out-to-top data-[state=open]:slide-in-from-top inset-x-0 top-0 h-auto border-b",
          side === "bottom" &&
            "data-[state=closed]:slide-out-to-bottom data-[state=open]:slide-in-from-bottom inset-x-0 bottom-0 h-auto border-t",
          className,
        )}
        {...props}
      >
        {children}
        {hideCloseButton ? null : (
